storage_seeds.files/style.css:
:root {
  --ink: #14201b;
  --paper: #f7faf8;
  --brand: #1f7a5a;
  --brand-soft: #e4f1ea;
  --muted: #5d6f67;
  --line: #d8e4dd;
}
* { box-sizing: border-box; }
body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Inter, system-ui, sans-serif;
  color: var(--ink);
  background: var(--paper);
  line-height: 1.6;
}
.page { max-width: 880px; margin: 0 auto; padding: 0 24px 64px; }
.hero { text-align: center; padding: 72px 0 48px; }
.badge {
  display: inline-block;
  padding: 5px 12px;
  border-radius: 999px;
  background: var(--brand-soft);
  color: var(--brand);
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 0.02em;
}
.hero h1 {
  margin: 18px 0 12px;
  font-size: clamp(34px, 7vw, 56px);
  line-height: 1.1;
  letter-spacing: -0.02em;
}
.lede { max-width: 600px; margin: 0 auto 28px; font-size: 18px; color: var(--muted); }
.cta {
  display: inline-block;
  padding: 13px 26px;
  border-radius: 12px;
  background: var(--brand);
  color: #fff;
  text-decoration: none;
  font-weight: 700;
  transition: transform 0.12s ease, box-shadow 0.12s ease;
}
.cta:hover { transform: translateY(-2px); box-shadow: 0 8px 24px rgba(31, 122, 90, 0.28); }
.features {
  display: grid;
  gap: 18px;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  margin-top: 24px;
}
.card {
  background: #fff;
  border: 1px solid var(--line);
  border-radius: 16px;
  padding: 22px 22px 24px;
}
.card h2 { margin: 0 0 8px; font-size: 19px; }
.card p { margin: 0; color: var(--muted); }
.foot { margin-top: 48px; text-align: center; color: var(--muted); font-size: 14px; }

